import{c as s,Q as n,j as l,m as i}from"./chunks/framework.CBiVa4O3.js";const u=JSON.parse('{"title":"系统设计系列写作计划","description":"","frontmatter":{},"headers":[],"relativePath":"../systemDesign/00-写作计划.md","filePath":"../systemDesign/00-写作计划.md","lastUpdated":1778496697000}'),t={name:"../systemDesign/00-写作计划.md"};function e(p,a,d,r,o,c){return n(),l("div",null,[...a[0]||(a[0]=[i(`<h1 id="系统设计系列写作计划" tabindex="-1">系统设计系列写作计划 <a class="header-anchor" href="#系统设计系列写作计划" aria-label="Permalink to &quot;系统设计系列写作计划&quot;">​</a></h1><blockquote><p>来源:<code>未来系列规划.md</code> 第一类「补完整知识图」第一项,⭐⭐⭐⭐⭐。 backendLearning 教了「用什么工具」(Spring / Redis / MQ / K8s),systemDesign 教「<strong>工具怎么组合应对真实流量</strong>」。这一层不补,后端知识就是一堆零件,拼不出能扛百万 QPS 的系统。 <strong>这个系列的目标读者</strong>:能独立写 CRUD、用过 Redis 和 MQ,但被问「Twitter 怎么设计」会卡住的工程师——也就是 3 ~ 5 年经验、卡在架构师之前那一层的人。</p></blockquote><hr><h2 id="设计思路" tabindex="-1">设计思路 <a class="header-anchor" href="#设计思路" aria-label="Permalink to &quot;设计思路&quot;">​</a></h2><p>四层结构,从「思考方式」到「真实案例」:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>心智与基础 (架构怎么想 / 容量估算 / CAP / 高可用)</span></span>
<span class="line"><span>   → 抗压基础设施 (LB / 缓存 / 分库 / MQ / 限流 / 一致性哈希)</span></span>
<span class="line"><span>   → 经典案例 (短链 → IM → 秒杀 → 12306)</span></span>
<span class="line"><span>   → 进阶 (多机房 / 容灾 / 灰度 / 设计文档)</span></span></code></pre></div><p>不重复 backendLearning 已经讲过的「Redis 数据结构」「K8s 工作负载」,而是聚焦<strong>这些工具怎么搭起来撑 1 亿用户</strong>。每篇案例都按「需求拆解 → 容量估算 → 数据模型 → 架构演进 → 关键取舍 → 失败模式」的固定模板,<strong>让你能模仿这个套路自己设计任何系统</strong>。</p><hr><h2 id="篇目-30-篇" tabindex="-1">篇目(30 篇) <a class="header-anchor" href="#篇目-30-篇" aria-label="Permalink to &quot;篇目(30 篇)&quot;">​</a></h2><h3 id="第一层-心智与基础-01-05" tabindex="-1">第一层:心智与基础(01-05) <a class="header-anchor" href="#第一层-心智与基础-01-05" aria-label="Permalink to &quot;第一层:心智与基础(01-05)&quot;">​</a></h3><ul><li>[x] 01 系统设计总览(怎么从模糊需求到架构图)</li><li>[x] 02 容量估算(QPS / 存储 / 带宽的快速心算)</li><li>[x] 03 架构演进史(单体 → 垂直拆分 → 微服务 → Mesh)</li><li>[x] 04 CAP / BASE / 一致性谱</li><li>[x] 05 高可用三件套(冗余 / 故障转移 / 健康检查)</li></ul><h3 id="第二层-抗压基础设施-06-13" tabindex="-1">第二层:抗压基础设施(06-13) <a class="header-anchor" href="#第二层-抗压基础设施-06-13" aria-label="Permalink to &quot;第二层:抗压基础设施(06-13)&quot;">​</a></h3><ul><li>[x] 06 负载均衡(L4 / L7 / DNS / Anycast / 反向代理)</li><li>[x] 07 缓存体系(本地 / 分布式 / CDN / 多级缓存)</li><li>[x] 08 数据库分库分表(垂直 / 水平 / 路由策略)</li><li>[x] 09 读写分离与复制(主从 / 多主 / 延迟与一致性)</li><li>[x] 10 消息队列与事件驱动(削峰 / 异步 / 解耦)</li><li>[x] 11 限流(令牌桶 / 漏桶 / 滑动窗口 / 分布式限流)</li><li>[x] 12 熔断 / 降级 / 隔离(Hystrix 思路)</li><li>[x] 13 一致性哈希与数据分布</li></ul><h3 id="第三层-经典案例-14-24" tabindex="-1">第三层:经典案例(14-24) <a class="header-anchor" href="#第三层-经典案例-14-24" aria-label="Permalink to &quot;第三层:经典案例(14-24)&quot;">​</a></h3><ul><li>[x] 14 短链系统(发号器 / 哈希 / 跳转性能)</li><li>[x] 15 登录与会话(亿级用户 SSO / Token / 黑名单)</li><li>[x] 16 Twitter / 微博(Timeline / 大 V 难题)</li><li>[x] 17 新闻 Feed(Push / Pull / Hybrid 推拉结合)</li><li>[x] 18 即时通讯(微信 / IM 长连接 / 消息可达)</li><li>[x] 19 视频点播(YouTube / B 站 / 转码 / CDN)</li><li>[x] 20 直播系统(推拉流 / 低延迟 / 弹幕)</li><li>[x] 21 网约车(地理位置 / 派单 / 实时定位)</li><li>[x] 22 秒杀系统(库存 / 反作弊 / 排队)</li><li>[x] 23 订单与支付(幂等 / 对账 / 分布式事务)</li><li>[x] 24 12306 / 票务(库存模型 / 候补 / 排队)</li></ul><h3 id="第四层-进阶与运维-25-30" tabindex="-1">第四层:进阶与运维(25-30) <a class="header-anchor" href="#第四层-进阶与运维-25-30" aria-label="Permalink to &quot;第四层:进阶与运维(25-30)&quot;">​</a></h3><ul><li>[x] 25 多机房与异地多活</li><li>[x] 26 容灾与备份(RTO / RPO / 故障演练)</li><li>[x] 27 数据迁移(在线 / 离线 / 双写)</li><li>[x] 28 灰度发布与蓝绿(流量切分 / 回滚)</li><li>[x] 29 全链路追踪与故障定位</li><li>[x] 30 设计文档与系统设计面试(怎么写 / 怎么答)</li></ul><hr><h2 id="完结-2026-05-09" tabindex="-1">完结(2026/05/09) <a class="header-anchor" href="#完结-2026-05-09" aria-label="Permalink to &quot;完结(2026/05/09)&quot;">​</a></h2><p>30 篇全部完成,一气呵成。整个系列严格按四层递进,每篇都遵守&quot;五段式 / 三段式&quot;模板,<strong>前后串联性强</strong>,后面案例篇可以套前面基础篇的概念。下一步:</p><ul><li>拿一个真实项目套五段式模板做一遍</li><li>从某个组件深挖到源码级(Redis Cluster / Kafka / TiDB 任选)</li><li>每月找一篇大厂技术博客练&quot;反向工程&quot;——他们的方案在哪一档</li></ul><hr><h2 id="与其他系列的边界" tabindex="-1">与其他系列的边界 <a class="header-anchor" href="#与其他系列的边界" aria-label="Permalink to &quot;与其他系列的边界&quot;">​</a></h2><table tabindex="0"><thead><tr><th>内容</th><th>已有系列</th><th>本系列</th></tr></thead><tbody><tr><td>Redis 数据结构与持久化</td><td>backendLearning/18-20 ✅</td><td>不重复,只讲「Redis 在系统里担当什么角色」</td></tr><tr><td>MySQL 索引与事务</td><td>backendLearning/13-14 ✅</td><td>不重复,只讲「分库分表的取舍」</td></tr><tr><td>K8s / Docker 基础</td><td>backendLearning/24-30 ✅</td><td>不重复,只讲「容器如何作为弹性单元」</td></tr><tr><td>限流熔断实现</td><td>backendLearning/43 ✅</td><td>互补,这里讲「为什么这么设计、单机 vs 分布式」</td></tr><tr><td>消息队列基础</td><td>backendLearning/31 ✅</td><td>互补,这里讲「在系统里怎么用 MQ 削峰解耦」</td></tr><tr><td>算法(一致性哈希 / LRU)</td><td>algorithms 系列(未写)</td><td>这里只讲「应用」,不讲「实现细节」</td></tr><tr><td>网络协议(HTTP/2/QUIC)</td><td>webLearning ✅</td><td>不重复,只讲「网关 / LB 如何选型」</td></tr><tr><td>分布式理论(Paxos / Raft)</td><td>distributed 系列(未写)</td><td>这里只讲「为什么这么选 / 工程影响」</td></tr></tbody></table><hr><h2 id="写作模板-每篇案例固定五段" tabindex="-1">写作模板(每篇案例固定五段) <a class="header-anchor" href="#写作模板-每篇案例固定五段" aria-label="Permalink to &quot;写作模板(每篇案例固定五段)&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 需求拆解</span></span>
<span class="line"><span>   - 功能需求(用户做什么)</span></span>
<span class="line"><span>   - 非功能需求(QPS / 数据规模 / 延迟 / 可用性)</span></span>
<span class="line"><span>   - 一句话画清边界:不做什么</span></span>
<span class="line"><span></span></span>
<span class="line"><span>2. 容量估算</span></span>
<span class="line"><span>   - DAU / QPS / 存储 / 带宽 的数量级估算</span></span>
<span class="line"><span>   - 算出来的数字直接决定后面架构选什么</span></span>
<span class="line"><span></span></span>
<span class="line"><span>3. 数据模型与核心算法</span></span>
<span class="line"><span>   - 表 / KV / 索引怎么设计</span></span>
<span class="line"><span>   - 关键操作的复杂度</span></span>
<span class="line"><span></span></span>
<span class="line"><span>4. 架构演进</span></span>
<span class="line"><span>   - 从「单机能扛」开始,逐步加缓存 → 加分库 → 加 MQ → 多活</span></span>
<span class="line"><span>   - 不要一上来就画终极版,展示推理过程</span></span>
<span class="line"><span></span></span>
<span class="line"><span>5. 关键取舍 / 失败模式</span></span>
<span class="line"><span>   - 选了 A 放弃了什么</span></span>
<span class="line"><span>   - 真实公司翻过哪些车</span></span></code></pre></div><p>**理论篇(01-13、25-30)**不套这个模板,但都遵守「为什么这样 → 实操怎么做 → 何时不该用」的三段式。</p><hr><h2 id="节奏" tabindex="-1">节奏 <a class="header-anchor" href="#节奏" aria-label="Permalink to &quot;节奏&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>01-05  「会设计」的最小心智集合,看完不会手脚发凉</span></span>
<span class="line"><span>06-13  抗压基础设施,这一段是「面试 / 实战」核心</span></span>
<span class="line"><span>14-24  把基础设施串成真实系统,选感兴趣的看</span></span>
<span class="line"><span>25-30  团队 / 大公司层面,按职业阶段决定</span></span></code></pre></div><p><strong>一个硬指标</strong>:看完前 13 篇,你应该能在白板前画出「短链 / 登录」的架构图,并答出每个组件的容量估算和故障模式。能做到的话这个系列就值了。</p><hr><h2 id="反对的写法" tabindex="-1">反对的写法 <a class="header-anchor" href="#反对的写法" aria-label="Permalink to &quot;反对的写法&quot;">​</a></h2><p>这个系列<strong>不写</strong>这些东西,见到了就是写错了:</p><ol><li>「先讲个故事」开头——直接进重点</li><li>罗列名词解释——讲清楚一个概念在系统里的「位置」比定义重要</li><li>「业内有 A、B、C、D 几种方案」然后并列讲——必须给出推荐和场景</li><li>把代码贴几百行——本系列以架构图、伪代码、表格为主</li><li>「面试经常问到」——读者来这里不是为了应付面试,是为了真的会</li><li>抄 Designing Data-Intensive Applications——那本书已经写得最好了,这里只补它没讲透的工程细节</li></ol>`,36)])])}const b=s(t,[["render",e]]);export{u as __pageData,b as default};
